## 🏆 信竞应用

### 1. 二分答案的充要条件

二分答案需要找到**单调性**的充要条件：

```cpp
// 例题：求最小的最大边权
// 问题：选择 k 条边，使得最大边权最小

bool check(int maxWeight) {
    // 判断是否存在 k 条边，权值都不超过 maxWeight
    int count = 0;
    for (int w : weights) {
        if (w <= maxWeight) {
            count++;
        }
    }
    return count >= k;  // 充要条件
}

int binarySearch() {
    int left = 0, right = 1e9;

    while (left < right) {
        int mid = left + (right - left) / 2;

        if (check(mid)) {
            // 满足条件，尝试更小的值
            right = mid;
        } else {
            // 不满足条件，需要更大的值
            left = mid + 1;
        }
    }

    return left;
}
```

### 2. 图论中的充要条件

**判断无向图是否有欧拉回路**：

```cpp
// 充要条件：所有顶点的度数都是偶数，且图连通
bool hasEulerCircuit(int n, vector<int> adj[]) {
    // 检查度数
    for (int i = 1; i <= n; i++) {
        if (adj[i].size() % 2 != 0) {
            return false;  // 有奇数度顶点，无欧拉回路
        }
    }

    // 检查连通性
    vector<bool> visited(n + 1, false);
    int start = 1;
    while (start <= n && adj[start].empty()) start++;

    if (start > n) return true;  // 空图

    function<void(int)> dfs = [&](int u) {
        visited[u] = true;
        for (int v : adj[u]) {
            if (!visited[v]) {
                dfs(v);
            }
        }
    };

    dfs(start);

    for (int i = 1; i <= n; i++) {
        if (!adj[i].empty() && !visited[i]) {
            return false;  // 不连通
        }
    }

    return true;  // 满足充要条件
}
```

### 3. 数论中的充要条件

**判断一个数是否为质数**：

```cpp
// 充要条件：除了 1 和自身外没有其他因数
bool isPrime(int n) {
    if (n < 2) return false;

    // 只需检查到 sqrt(n)
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            return false;
        }
    }

    return true;
}

// 费马小定理（必要不充分条件）
// 如果 p 是质数，则 a^(p-1) ≡ 1 (mod p)
// 但满足这个条件的不一定是质数（伪质数）
long long power(long long base, long long exp, long long mod) {
    long long result = 1;
    base %= mod;
    while (exp > 0) {
        if (exp & 1) result = result * base % mod;
        base = base * base % mod;
        exp >>= 1;
    }
    return result;
}

bool fermatTest(int p, int a = 2) {
    if (p < 2) return false;
    return power(a, p - 1, p) == 1;
}
// 注意：这是必要不充分条件，只能用于排除合数
```

### 4. 动态规划的最优子结构

**最优子结构**是 DP 的充要条件：

```cpp
// 最长上升子序列 (LIS)
// 充要条件：最优解包含子问题的最优解

int lengthOfLIS(vector<int>& nums) {
    int n = nums.size();
    vector<int> dp(n, 1);  // dp[i] 表示以 nums[i] 结尾的 LIS 长度

    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (nums[j] < nums[i]) {
                // 最优子结构：LIS(i) = max(LIS(j)) + 1
                dp[i] = max(dp[i], dp[j] + 1);
            }
        }
    }

    return *max_element(dp.begin(), dp.end());
}
```

