        for (int v : adj[u]) {
            if (!visited[v]) {
                dfs(v);
            }
        }
    };

    dfs(start);

    for (int i = 1; i <= n; i++) {
        if (!adj[i].empty() && !visited[i]) {
            return false;  // 不连通
        }
    }

    return true;  // 满足充要条件
}
```

### 3. 数论中的充要条件

**判断一个数是否为质数**：

```cpp
// 充要条件：除了 1 和自身外没有其他因数
bool isPrime(int n) {
    if (n < 2) return false;

    // 只需检查到 sqrt(n)
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            return false;
        }
    }

    return true;
}

// 费马小定理（必要不充分条件）
// 如果 p 是质数，则 a^(p-1) ≡ 1 (mod p)
// 但满足这个条件的不一定是质数（伪质数）
long long power(long long base, long long exp, long long mod) {
    long long result = 1;
    base %= mod;
    while (exp > 0) {
        if (exp & 1) result = result * base % mod;
        base = base * base % mod;
        exp >>= 1;
    }
    return result;
}

bool fermatTest(int p, int a = 2) {
    if (p < 2) return false;
    return power(a, p - 1, p) == 1;
}
// 注意：这是必要不充分条件，只能用于排除合数
```

### 4. 动态规划的最优子结构

**最优子结构**是 DP 的充要条件：

```cpp
// 最长上升子序列 (LIS)
// 充要条件：最优解包含子问题的最优解

int lengthOfLIS(vector<int>& nums) {
    int n = nums.size();
    vector<int> dp(n, 1);  // dp[i] 表示以 nums[i] 结尾的 LIS 长度

    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (nums[j] < nums[i]) {
                // 最优子结构：LIS(i) = max(LIS(j)) + 1
                dp[i] = max(dp[i], dp[j] + 1);
            }
        }
    }

    return *max_element(dp.begin(), dp.end());
}
```

