## 💻 代码实现

### 函数的 C++ 实现

```cpp
#include <bits/stdc++.h>
using namespace std;

// 1. 基本函数定义
int square(int x) {
    return x * x;
}

// 2. 带默认参数的函数
int power(int x, int n = 2) {
    int result = 1;
    for (int i = 0; i < n; i++) {
        result *= x;
    }
    return result;
}

// 3. 分段函数
int piecewise(int x) {
    if (x < 0) return x;
    else if (x < 1) return x * x;
    else return 2 * x - 1;
}

// 4. 递归函数（斐波那契）
int fibonacci(int n) {
    if (n <= 1) return n;
    return fibonacci(n - 1) + fibonacci(n - 2);
}

// 5. 函数作为参数（回调函数）
int apply(int x, int (*func)(int)) {
    return func(x);
}

int main() {
    cout << square(5) << endl;        // 25
    cout << power(3) << endl;         // 9 (默认平方)
    cout << power(2, 3) << endl;      // 8
    cout << piecewise(-2) << endl;    // -2
    cout << fibonacci(10) << endl;    // 55
    cout << apply(4, square) << endl; // 16

    return 0;
}
```

### 函数在信竞中的应用

**1. 数学公式直接实现**

```cpp
// 计算两点间距离
double distance(double x1, double y1, double x2, double y2) {
    return sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
}

// 计算组合数 C(n, m)
long long combination(int n, int m) {
    if (m > n) return 0;
    if (m == 0 || m == n) return 1;

    long long result = 1;
    for (int i = 1; i <= m; i++) {
        result = result * (n - i + 1) / i;
    }
    return result;
}
```

**2. 状态转移函数（DP）**

```cpp
// 最长上升子序列的状态转移
int lis(const vector<int>& nums) {
    int n = nums.size();
    vector<int> dp(n, 1);  // dp[i] 表示以 nums[i] 结尾的 LIS 长度

    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (nums[j] < nums[i]) {
                dp[i] = max(dp[i], dp[j] + 1);
            }
        }
    }

    return *max_element(dp.begin(), dp.end());
}
```

**3. 哈希函数**

```cpp
// 简单的字符串哈希函数
unsigned long long hash_string(const string& s) {
    unsigned long long hash = 0;
    unsigned long long base = 131;

    for (char c : s) {
        hash = hash * base + c;
    }

    return hash;
}

// 判断两个字符串是否相等（哈希比较）
bool equal_hash(const string& a, const string& b) {
    return hash_string(a) == hash_string(b);
}
```

### 函数的时间复杂度分析

```cpp
// O(1) - 常数时间
int constant(int x) {
    return x * x;
}

// O(n) - 线性时间
int linear(int n) {
    int sum = 0;
    for (int i = 1; i <= n; i++) {
        sum += i;
    }
    return sum;
}

// O(n²) - 平方时间
int quadratic(int n) {
    int sum = 0;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            sum += i * j;
        }
    }
    return sum;
}

// O(log n) - 对数时间
int logarithmic(int n) {
    int count = 0;
    while (n > 1) {
        n /= 2;
        count++;
    }
    return count;
}

// O(2^n) - 指数时间
int exponential(int n) {
    if (n <= 1) return 1;
    return exponential(n - 1) + exponential(n - 1);
}
```

