## 💻 代码实现

### 判断函数奇偶性

```cpp
#include <bits/stdc++.h>
using namespace std;

// 示例函数
int f_square(int x) {
    return x * x;  // 偶函数
}

int f_cube(int x) {
    return x * x * x;  // 奇函数
}

int f_linear(int x) {
    return 2 * x + 1;  // 非奇非偶
}

// 判断函数奇偶性
string check_parity(int (*func)(int), int test_range = 100) {
    bool is_even = true;
    bool is_odd = true;

    for (int x = 1; x <= test_range; x++) {
        int fx = func(x);
        int f_neg_x = func(-x);

        if (f_neg_x != fx) {
            is_even = false;
        }
        if (f_neg_x != -fx) {
            is_odd = false;
        }

        // 提前退出
        if (!is_even && !is_odd) {
            return "非奇非偶函数";
        }
    }

    if (is_even) return "偶函数";
    if (is_odd) return "奇函数";
    return "非奇非偶函数";
}

int main() {
    cout << "f(x) = x²: " << check_parity(f_square) << endl;
    cout << "f(x) = x³: " << check_parity(f_cube) << endl;
    cout << "f(x) = 2x+1: " << check_parity(f_linear) << endl;

    return 0;
}
```

### 利用奇偶性简化计算

```cpp
// 计算对称区间上的函数值和
// 如果 f(x) 是奇函数，则 sum = 0
// 如果 f(x) 是偶函数，则 sum = 2 * sum(0 to n)

// 奇函数：f(x) = x³
long long sum_odd_function(int n) {
    // f(x) = x³ 是奇函数
    // sum(-n to n) = 0
    return 0;  // 直接返回 0，无需计算
}

// 偶函数：f(x) = x²
long long sum_even_function(int n) {
    // f(x) = x² 是偶函数
    // sum(-n to n) = 2 * sum(0 to n)
    long long sum = 0;
    for (int x = 0; x <= n; x++) {
        sum += x * x;
    }
    return 2 * sum - 0;  // 减去重复计算的 f(0)
}

// 一般情况
long long sum_general(int (*func)(int), int n) {
    // 先判断奇偶性
    bool is_even = true;
    bool is_odd = true;

    for (int x = 1; x <= min(n, 100); x++) {
        if (func(-x) != func(x)) is_even = false;
        if (func(-x) != -func(x)) is_odd = false;
    }

    if (is_odd) {
        return 0;  // 奇函数在对称区间和为 0
    } else if (is_even) {
        long long sum = 0;
        for (int x = 0; x <= n; x++) {
            sum += func(x);
        }
        return 2 * sum - func(0);
    } else {
        // 非奇非偶，直接计算
        long long sum = 0;
        for (int x = -n; x <= n; x++) {
            sum += func(x);
        }
        return sum;
    }
}
```

### 奇偶性在位运算中的应用

```cpp
// 判断一个数的二进制中 1 的个数的奇偶性
bool has_odd_ones(int n) {
    int count = 0;
    while (n > 0) {
        count += n & 1;
        n >>= 1;
    }
    return count % 2 == 1;
}

// 更高效的实现（异或所有位）
bool has_odd_ones_fast(int n) {
    bool parity = false;
    while (n > 0) {
        parity ^= (n & 1);
        n >>= 1;
    }
    return parity;
}

// 使用内置函数（GCC）
bool has_odd_ones_builtin(int n) {
    return __builtin_parity(n);  // 返回 1 的个数的奇偶性
}
```

