    cout << "ln(e) = " << log(M_E) << endl;  // 1.0

    // 常用对数
    cout << "lg(100) = " << log10(100) << endl;  // 2.0

    // 以 2 为底的对数
    cout << "lb(8) = " << log2(8) << endl;  // 3.0

    // 换底公式：logₐ(b) = ln(b) / ln(a)
    cout << "log₃(9) = " << log(9) / log(3) << endl;  // 2.0

