// O(log n) 的例子：二分查找

int binary_search(const vector<int>& nums, int target) {
    int left = 0, right = nums.size() - 1;
    int steps = 0;

    while (left <= right) {
        steps++;
        int mid = left + (right - left) / 2;

        if (nums[mid] == target) {
            cout << "找到目标，用了 " << steps << " 步" << endl;
            return mid;
        } else if (nums[mid] < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    cout << "未找到，用了 " << steps << " 步" << endl;
    return -1;
}

// 对于 n 个元素，最多需要 log₂(n) 步
// n = 1000 → log₂(1000) ≈ 10 步
// n = 1000000 → log₂(1000000) ≈ 20 步
```

### 对数优化乘法

```cpp
// 用对数将乘法转化为加法（避免溢出）
// log(a × b) = log(a) + log(b)

double log_multiply(double a, double b) {
    return exp(log(a) + log(b));
}

// 应用：计算多个大数的乘积
double product_of_large_numbers(const vector<double>& nums) {
    double log_sum = 0;
    for (double x : nums) {
        log_sum += log(x);
    }
    return exp(log_sum);
}
```

